#include "InventoryController.h"
#include "../plugins/InventoryService.h"
#include "../AuditLog.h"
using namespace drogon;
namespace {HttpResponsePtr out(Json::Value j,HttpStatusCode c=k200OK){auto r=HttpResponse::newHttpJsonResponse(j);r->setStatusCode(c);return r;}HttpResponsePtr err(std::string s,HttpStatusCode c=k400BadRequest){Json::Value j;j["error"]=s;return out(j,c);}bool manager(const HttpRequestPtr&r){try{return r->attributes()->get<std::string>("role")=="manager";}catch(...){return false;}}struct PageQuery{int limit=100,offset=0;std::optional<int64_t>from,to;};PageQuery page(const HttpRequestPtr&r,bool dates=true){PageQuery q;if(!r->getParameter("limit").empty())q.limit=std::stoi(r->getParameter("limit"));if(!r->getParameter("offset").empty())q.offset=std::stoi(r->getParameter("offset"));if(q.limit<1||q.limit>500||q.offset<0)throw std::invalid_argument("limit must be 1..500 and offset must be non-negative");if(dates){if(!r->getParameter("from").empty())q.from=std::stoll(r->getParameter("from"));if(!r->getParameter("to").empty())q.to=std::stoll(r->getParameter("to"));if(q.from&&q.to&&*q.from>*q.to)throw std::invalid_argument("from must not be after to");}return q;}Json::Value envelope(Json::Value data,const PageQuery&q){Json::Value x;x["items"]=std::move(data);x["limit"]=q.limit;x["offset"]=q.offset;if(q.from)x["from"]=Json::Int64(*q.from);if(q.to)x["to"]=Json::Int64(*q.to);return x;}}
Task<HttpResponsePtr> InventoryController::items(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);try{auto q=page(r,false);bool active=r->getParameter("active_only")=="true";auto v=co_await app().getPlugin<InventoryService>()->items(q.limit,q.offset,active);Json::Value a(Json::arrayValue);for(auto&i:v){Json::Value j;j["id"]=i.id;j["name"]=i.name;j["unit"]=i.unit;j["is_active"]=i.is_active;j["on_hand"]=i.on_hand;a.append(j);}auto x=envelope(std::move(a),q);x["active_only"]=active;co_return out(x);}catch(const std::invalid_argument&e){co_return err(e.what());}catch(const std::exception&e){co_return err(e.what(),k500InternalServerError);}}
Task<HttpResponsePtr> InventoryController::createItem(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();if(!j)co_return err("Invalid JSON");try{auto id=co_await app().getPlugin<InventoryService>()->createItem((*j)["name"].asString(),(*j)["unit"].asString());Json::Value x;x["id"]=id;co_return out(x,k201Created);}catch(std::exception&e){co_return err(e.what());}}
Task<HttpResponsePtr> InventoryController::updateItem(HttpRequestPtr r,int64_t id){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();if(!j)co_return err("Invalid JSON");try{Json::Value before;for(auto&i:co_await app().getPlugin<InventoryService>()->items())if(i.id==id){before["name"]=i.name;before["unit"]=i.unit;before["is_active"]=i.is_active;}bool ok=co_await app().getPlugin<InventoryService>()->updateItem(id,(*j)["name"].asString(),(*j)["unit"].asString(),j->get("is_active",true).asBool());Json::Value x;x["success"]=ok;if(ok)writeChangeAudit(r,"SỬA NGUYÊN LIỆU","inventory_item#"+std::to_string(id),before,*j,{"name","unit","is_active"});co_return out(x,ok?k200OK:k404NotFound);}catch(std::exception&e){co_return err(e.what());}}
Task<HttpResponsePtr> InventoryController::lots(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);try{auto q=page(r);auto v=co_await app().getPlugin<InventoryService>()->lots(q.limit,q.offset,q.from,q.to);Json::Value a(Json::arrayValue);for(auto&i:v){Json::Value j;j["id"]=i.id;j["item_id"]=i.item_id;j["item_name"]=i.item_name;j["quantity"]=i.quantity;j["remaining"]=i.remaining;j["unit_cost"]=i.unit_cost;j["purchased_at"]=i.purchased_at;j["expires_at"]=i.expires_at;j["is_void"]=i.is_void;a.append(j);}co_return out(envelope(std::move(a),q));}catch(const std::invalid_argument&e){co_return err(e.what());}catch(const std::exception&e){co_return err(e.what(),k500InternalServerError);}}
Task<HttpResponsePtr> InventoryController::createLot(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();if(!j)co_return err("Invalid JSON");try{auto id=co_await app().getPlugin<InventoryService>()->createLot((*j)["item_id"].asInt64(),(*j)["quantity"].asDouble(),(*j)["unit_cost"].asInt64(),(*j)["purchased_at"].asInt64(),(*j)["expires_at"].asInt64(),j->get("note","").asString());Json::Value x;x["id"]=id;co_return out(x,k201Created);}catch(std::exception&e){co_return err(e.what());}}
Task<HttpResponsePtr> InventoryController::voidLot(HttpRequestPtr r,int64_t id){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();Json::Value before;for(auto&i:co_await app().getPlugin<InventoryService>()->lots())if(i.id==id){before["quantity"]=i.quantity;before["unit_cost"]=i.unit_cost;before["purchased_at"]=i.purchased_at;before["expires_at"]=i.expires_at;before["is_void"]=i.is_void;}bool ok=co_await app().getPlugin<InventoryService>()->voidLot(id,j?j->get("note","voided by manager").asString():"voided by manager");Json::Value x;x["success"]=ok;if(ok){Json::Value after=before;after["is_void"]=true;writeChangeAudit(r,"HỦY LÔ KHO","inventory_lot#"+std::to_string(id),before,after,{"quantity","unit_cost","purchased_at","expires_at","is_void"});}co_return out(x,ok?k200OK:k404NotFound);}
Task<HttpResponsePtr> InventoryController::recipes(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);try{auto q=page(r,false);std::optional<int64_t>p;if(!r->getParameter("product_id").empty())p=std::stoll(r->getParameter("product_id"));bool active=r->getParameter("active_only")=="true";auto v=co_await app().getPlugin<InventoryService>()->recipes(p,q.limit,q.offset,active);Json::Value a(Json::arrayValue);for(auto&i:v){Json::Value j;j["id"]=i.id;j["product_id"]=i.product_id;j["item_id"]=i.item_id;j["item_name"]=i.item_name;j["unit"]=i.unit;j["quantity"]=i.quantity;j["is_active"]=i.is_active;a.append(j);}auto x=envelope(std::move(a),q);x["active_only"]=active;co_return out(x);}catch(const std::invalid_argument&e){co_return err(e.what());}catch(const std::exception&e){co_return err(e.what(),k500InternalServerError);}}
Task<HttpResponsePtr> InventoryController::createRecipe(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();if(!j)co_return err("Invalid JSON");try{auto id=co_await app().getPlugin<InventoryService>()->createRecipe((*j)["product_id"].asInt64(),(*j)["item_id"].asInt64(),(*j)["quantity"].asDouble());Json::Value x;x["id"]=id;co_return out(x,k201Created);}catch(std::exception&e){co_return err(e.what());}}
Task<HttpResponsePtr> InventoryController::updateRecipe(HttpRequestPtr r,int64_t id){if(!manager(r))co_return err("Permission denied",k403Forbidden);auto j=r->getJsonObject();if(!j)co_return err("Invalid JSON");try{Json::Value before;for(auto&i:co_await app().getPlugin<InventoryService>()->recipes(std::nullopt))if(i.id==id){before["quantity"]=i.quantity;before["is_active"]=i.is_active;}bool ok=co_await app().getPlugin<InventoryService>()->updateRecipe(id,(*j)["quantity"].asDouble(),j->get("is_active",true).asBool());Json::Value x;x["success"]=ok;if(ok)writeChangeAudit(r,"SỬA CÔNG THỨC","recipe#"+std::to_string(id),before,*j,{"quantity","is_active"});co_return out(x,ok?k200OK:k404NotFound);}catch(std::exception&e){co_return err(e.what());}}
Task<HttpResponsePtr> InventoryController::movements(HttpRequestPtr r){if(!manager(r))co_return err("Permission denied",k403Forbidden);try{auto q=page(r);std::optional<std::string>kind;if(!r->getParameter("kind").empty()){kind=r->getParameter("kind");if(*kind!="purchase"&&*kind!="void_purchase"&&*kind!="sale"&&*kind!="sale_adjustment")throw std::invalid_argument("unsupported movement kind");}auto v=co_await app().getPlugin<InventoryService>()->movements(q.limit,q.offset,q.from,q.to,kind);Json::Value a(Json::arrayValue);for(auto&i:v){Json::Value j;j["id"]=Json::Int64(i.id);j["item_id"]=Json::Int64(i.item_id);j["item_name"]=i.item_name;j["unit"]=i.unit;if(i.lot_id)j["lot_id"]=Json::Int64(*i.lot_id);j["quantity_delta"]=i.quantity_delta;j["kind"]=i.kind;j["reference_type"]=i.reference_type;if(i.reference_id)j["reference_id"]=Json::Int64(*i.reference_id);j["note"]=i.note;j["created_at"]=Json::Int64(i.created_at);a.append(j);}auto x=envelope(std::move(a),q);if(kind)x["kind"]=*kind;co_return out(x);}catch(const std::invalid_argument&e){co_return err(e.what());}catch(const std::exception&e){co_return err(e.what(),k500InternalServerError);}}
